_NuFrRa_async (c, r) => {
    let a = await r("php please list --format=json"),
        t = [];

    try {
      JSON.parse(a).commands.map(n => {
        t.push({
          name: n.name,
          description: n.description,
          args: Object.values(n.definition.arguments).map(e => ({
            name: e.name,
            description: e.description,
            isOptional: !e.is_required
          })),
          options: Object.values(n.definition.options).map(e => {
            let s = [e.name];
            return e.shortcut !== "" && s.push(e.shortcut), {
              name: s,
              description: e.description
            };
          })
        });
      });
    } catch (i) {
      console.error(i);
    }

    return {
      name: "please",
      debounce: !0,
      subcommands: t
    };
  }
